    // --- Check possibility for all ODD ---
    let allOddPossible = false;

    if (odds.length > 0) {
        // Find the minimum odd number
        let o_min = odds[0];
        for (let i = 1; i < odds.length; i++) {
            if (odds[i] < o_min) {
                o_min = odds[i];
            }
        }

        // For all odd target, every even number E must be convertible to odd.
        // This requires E > o_min, so that E - o_min >= 1 and is odd.
        let canAchieveAllOdd = true;
        for (const E of evens) {
            if (E <= o_min) {
                canAchieveAllOdd = false;
                break;
            }
        }
        allOddPossible = canAchieveAllOdd;
    } else {
        // If there are no odd numbers, all elements are even. 
        // We cannot create an odd number via differences (Even - Even = Even), 
        // nor can we use the original even numbers.
        allOddPossible = false;
    }

    return allEvenPossible || allOddPossible;
}

